import { createApp } from 'vue'
import App from './App.vue'
import router from './router'
import store from './store'
import ElementPlus from 'element-plus'
import 'element-plus/dist/index.css'
import zhCn from 'element-plus/es/locale/lang/zh-cn'

// 导入ECharts，改用CDN加载
// 创建script标签加载ECharts和wordcloud扩展
const loadScripts = () => {
  const echartsScript = document.createElement('script');
  echartsScript.src = 'https://cdn.bootcdn.net/ajax/libs/echarts/5.4.3/echarts.min.js';
  echartsScript.async = false;
  document.head.appendChild(echartsScript);

  // 在ECharts加载完成后加载wordcloud扩展
  echartsScript.onload = () => {
    const wordcloudScript = document.createElement('script');
    wordcloudScript.src = 'https://cdnjs.cloudflare.com/ajax/libs/echarts-wordcloud/2.1.0/echarts-wordcloud.min.js';
    wordcloudScript.async = false;
    document.head.appendChild(wordcloudScript);
  };
};

// 加载脚本
loadScripts();

// 忽略 ResizeObserver 循环错误
const originalConsoleError = window.console.error;
window.console.error = (...args) => {
  if (args[0] && typeof args[0] === 'string' && args[0].includes('ResizeObserver loop')) {
    return;
  }
  originalConsoleError(...args);
};

// 创建Vue应用
const app = createApp(App)

// 使用插件
app.use(router)
app.use(store)
app.use(ElementPlus, {
  locale: zhCn
})

// 挂载应用
app.mount('#app')
